import{_ as b,o as a,c as e,j as r,a as s,a1 as t}from"./chunks/framework.Bp7r_-XI.js";const c=JSON.parse('{"title":"深海猎人（Abyssal Hunters）","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/深海猎人（Abyssal Hunters）.md","filePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/深海猎人（Abyssal Hunters）.md"}'),n={name:"4.资源分区/2.改造与功法/改造/6.一次性改造/深海猎人（Abyssal Hunters）.md"};function l(o,p,d,_,u,h){return a(),e("div",null,[...p[0]||(p[0]=[r("h1",{id:"深海猎人-abyssal-hunters",tabindex:"-1"},[s("深海猎人（Abyssal Hunters） "),r("a",{class:"header-anchor",href:"#深海猎人-abyssal-hunters","aria-label":'Permalink to "深海猎人（Abyssal Hunters）"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),t('<h1 id="深海猎人-abyssal-hunters-1" tabindex="-1">深海猎人（Abyssal Hunters） <a class="header-anchor" href="#深海猎人-abyssal-hunters-1" aria-label="Permalink to &quot;深海猎人（Abyssal Hunters）&quot;">​</a></h1><p>深海猎人（Abyssal Hunters）<br> B+5400<br> 一次性改造<br> 特异本质</p><p>深海猎人是隶属于深海国家阿戈尔的军事力量，主要在阿戈尔地区活动。</p><p>深海猎人成立的宗旨是对抗海洋生物“海嗣”及其追随者深海教会，以避免其对阿戈尔地区乃至泰拉世界进行突袭。</p><p>深海猎人并非完全的阿戈尔人，这些用于抵御怪物的战士通过阿戈尔的改造技术被植入了海嗣的血统，由此，他们获得了超乎常人的能力，能从最致命的伤势中存活下来并快速自愈；但另一方面，海嗣的血统对深海猎人成员也有着负面影响：当他们精神受创时，心理开始极其不稳定，随后逐渐屈服于本能，甚至完全转化为海嗣。</p><p>阿戈尔海巡队作为深海猎人的监视部队将会在猎人怪物化以后予以捕杀。</p><p>【人造兵器】： <br> “深海猎人……是阿戈尔创造出来，用以对抗海嗣的战争机器。<br> 我们被设计、被制造，从诞生之初就只有一个目标：狩猎那些怪物。”</p><p>深海猎人并非自然种族，而是由科技高度发达的文明人为创造的特殊战士，从现在开始，你在判定种族时，额外视作【深海猎人】种族，在对方试图探查你的种族时可以被感知，特殊情况下水生种族可能会有额外的反应，获得等同于基础移动速度的游泳速度，并且可以在水下呼吸，你额外获得黑暗视觉，此外你在生理属性检定上获得等同于生理属性上的传奇属性之和*1点的增强加值，额外获得等同于生理属性上的传奇属性之和*1的生命值上限。</p><p>【涨潮】：<br> &quot;深海猎人因海嗣的力量而诞生……<br> 我们的血液在杀死它们的同时，也在将自身转化为它们。<br> 这是阿戈尔给予我们的永恒枷锁——终将归海。&quot;</p><p>深海猎人对抗海嗣的力量，本身就来源于海嗣，海嗣可主动选择突变方向，通过战斗或吞噬快速进化出适应性特征（如抗性、新器官），且无劣化风险，猎人们获得B级环境来源的免疫效果和三防效果。</p><p>【血脉相连】：</p><p>虽然是人造的，但深海猎人之间存在着一种类似“血缘”的深刻联系。他们彼此能感知到对方的存在和状态（尤其是强烈的情绪或危机），并称呼彼此为“同胞”。</p><p>这种联系不仅源于创造方式，更源于他们共享的命运和对抗共同敌人的经历。</p><p>阿戈尔文档<br> C+1000<br> 占据护符位</p><p>“会进化的并不只有海嗣，深海猎人们也在不断成长。”</p><p>若持有者为【深海猎人】，若你在该影片中在一场同级战斗中胜出，在本场影片结束时，你获得1点生理属性检定上的增强加值和生命值上限，最多以此法成长16次。</p><p>深海再生力<br> B+2000</p><p>当她祈祷<br> 星星停止闪烁<br> 当她流泪<br> 夜晚露出微笑<br> 当她悲叹<br> 痛苦蔓延在她的疯狂</p><p>兑换者每从【深海猎人】及其下属中获得7点生命值，就获得1点快速医疗，每点快速医疗附带12点医疗点，<br> 特殊的，若兑换者同时被【阿戈尔的波涛】影响，那么他获得的快速医疗点数不会叠加，而是会取高计算，医疗点也取高计算。<br> 你现在可以同时攻击触及范围内的全部敌人，你的攻击额外具有破甲5。</p><p>从不混淆的方向<br> B+3500<br> 我并不在意他是出于责任心还是忧虑感，重点是他成功了。<br> 在深海猎人里，乌尔比安的身体机能数据谈不上有多么突出，单论耐力或者速度，他比不上斯卡蒂和我。但他选择了最合适的武器与战斗方式，节制地、精准地倾泻自己的暴力——这也是他常常教育斯卡蒂的。他成为阿戈尔第一位深海猎人，并战斗到了最后，直到现在背离阿戈尔而去。他的可靠与危险都来源于此。</p><p>当你兑换该技艺后，失去所有的基础防御和基础防御上的附加成功，转而获得【敏捷+感知】/2的生命值上限。<br> 若你因为某些原因导致没有足够的基础防御和附加成功，那么你转而失去基础防御基于的防御类型，若此时对应防御上没有附加成功，那么每点附加成功视作3点防御计算失去的防御，若基础防御基于的防御类型不足，则转而按照闪避-洞察-格挡-遮蔽-器械-天生-盔甲-力场-偏斜-能量-无名防御的顺序扣除对应的防御，直到扣除的防御数值等同于应失去的防御为止。<br> 你的攻击可以同时命中触及范围内的所有敌人。</p><p>本性的坚守<br> A+4000<br> “没有无效的答案，决定答案价值的是问题本身。真正发现问题所在，才能解决它。”<br> 他仍会歌唱......在那只杂碎吞吃了阿玛雅、“愚人号”附近的整片海域都陷入静谧的时候，在弥利亚留姆的信标塔彻底沉入海底的时候......我绝对听到过。</p><p>兑换该技艺后，你获得传奇耐力*1点快速医疗，每点快速医疗附带12医疗点，当你的完好被严重伤害填满时，你以此法获得的快速医疗翻倍。<br> 一轮一次，当你受到攻击时，你可以使用一个反射动作调用该技艺，使你持有的所有快速医疗立刻生效一次，这是一个【竭取】效果。</p><p>【特殊的：若无专门说明，则下列需要阿戈尔文档的技艺之间互斥】</p><p>血脉的哺养<br> B+4500<br> 购买前置：阿戈尔文档</p><p>当研究终于进入临床阶段时，他选择在自己身上融入那些异种的血肉，进行尚未成熟的基因改造手术......<br> 代价？与整个项目失去负责人和核心科研人员这件事相比，他身上的累累伤痕只不过是最小的代价。</p><p>你每杀死1名敌人都会在该影片内获得1点额外的生命值上限和1点力量检定上的表现加值，最多叠加9次。<br> 以你为中心，以30M为半径的圆形区域内的【深海猎人】们同样可以获得这个效果，但是他们获得的效果减半，且获得的生命值上限变为临时生命，即最多获得4点临时生命和4点力量加值。</p><p>阿戈尔的波涛<br> B+2000<br> 购买前置：阿戈尔文档</p><p>“我的亲人，是认同、支持、养育我的人，而不是将遗传基因传递给我的人。我的新家庭与我没有血缘关系，大多数阿戈尔人都是如此。<br> 陆上人是无法接受阿戈尔的。无论是阿戈尔的文化，还是阿戈尔的知识，都不可能给他们带来益处。<br> 勿予蛮人以凶器。”</p><p>兑换该技艺后，你每从【深海猎人】及其下属资源中获得7点生命值上限，那么你周围30米范围内、除你以外的属于深海猎人的友方单位就获得1点快速医疗，每点快速医疗附带12点医疗点，多个单位生效会共同消耗同一医疗点池。<br> 该技艺自带40点医疗点。</p><p>深海掠食者<br> B+2000<br> 购买前置：阿戈尔文档</p><p>【如果说干员斯卡蒂的体质令人生畏，那么她所造成的破坏更是匪夷所思。<br> 常有干员在与斯卡蒂一同执行任务归来后，在报告中过度渲染干员斯卡蒂的身体能力，将干员斯卡蒂描摹成变异的童话故事或传统民谣记述的怪物等。】</p><p>兑换该技艺后，你的力量检定上获得【8加骰】，并且可以将力量上的附加成功转化为4DP，最多以此法转化力量上的传奇属性*1点。<br> 以你为中心，以30M为半径的圆形区域内的【深海猎人】们同样可以获得这个效果，但是他们不会获得【8加骰】，而是转而获得2点力量检定上的增强加值。</p><p>阿戈尔的深邃<br> B+3500<br> 购买前置：阿戈尔文档</p><p>【深海猎人在海面上遇到的问题，在海面下也别无二致。<br> 然而以现在的人力，深海猎人无法改变任何事情，而面对以阿戈尔的科学技术尚无法完全驱逐的海嗣祸患，陆上人那些粗浅的科技又能做到什么呢？<br> 这就是深海猎人们的现状，歌蕾蒂娅一直对此抱有忧虑，这一点幽灵鲨很清楚。】</p><p>兑换该技艺后，你的生命值上限额外增加生理属性上的传奇属性之和*1点，<br> 以你为中心，以30M为半径的圆形区域内的【深海猎人】们同样可以获得这个效果，但是他们获得的并非生命值上限，而是其自身耐力上的传奇属性*2点临时生命，这部分临时生命一日只会生效一次。</p><p>深海直觉<br> B+2000<br> 购买前置：阿戈尔文档</p><p>【闭上眼的时候，我会看到一个人。我完全没有印象，但毫无疑问，那个人就是这个麻烦漩涡的中心。<br> 一个披着海水气味的人，一个穿着长袍的伊比利亚人......】</p><p>兑换该技艺后，你的攻击额外获得B级措手不及，<br> 以你为中心，以30M为半径的圆形区域内的【深海猎人】们同样可以获得这个效果，但是他们不会获得B级措手不及，而是转而获得额外的10高速。</p><p>潮涌悲歌<br> A+4000</p><p>一个不属于人类的怪物，一个不属于海嗣的人类。<br> 躲在这潮水中，胆怯地望向代表着美好的符号。<br> 她想要现身，她害怕现身。<br> 唯一能做的，只是远远望上一眼，稍稍填补心灵上的空缺，随后，被更大的罪恶感所淹没。<br> 生存成为了累赘，可死亡又是那么遥远。<br> 她成为了空虚的具象。<br> ……<br> 斯卡蒂喉中涌上了一支歌谣。<br> 她唱过千百遍，每个音节，每次发声都早已至臻完美。<br> 可现在听来，这首歌像是落在地上的玻璃，<br> 碎成千百块，再也补不回来。<br> 然而她还是唱着，唱着。<br> 歌唱是她仅剩的本能。<br> 歌曲不能赎罪，也无法平息悲伤。<br> 但她还是流着泪歌唱。<br> 心绪颤动带走了歌喉的音准。<br> 泪水落在舌尖上，苦涩流入心田。<br> 喉头逐渐变得红肿，歌谣时常被呜咽打断。<br> 但她还是唱着，唱着。<br> 她不需要听众，也不奢望听众。<br> 如果歌唱是她生命中唯一留存下来的意义。<br> 那就唱吧。</p><p>以一个杂技动作启用，在该场景中，你从【深海猎人】改造本体获得的生命值上限翻倍，<br> 你始终视作已进行全防御，你每轮首次攻击造成的伤害翻倍。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',44)])])}const y=b(n,[["render",l]]);export{c as __pageData,y as default};
